namespace sv_e71bdc2613884f5585f6babd2d1f7454.Services;

public class AppointmentService
{
    private static readonly List<string> Doctors =
    [
        "Dr. Smith",
        "Dr. Johnson",
        "Dr. Williams",
        "Dr. Patel"
    ];

    private static readonly List<string> TimeSlots =
    [
        "9:00 AM",
        "9:30 AM",
        "10:00 AM",
        "10:30 AM",
        "11:00 AM",
        "1:00 PM",
        "1:30 PM",
        "2:00 PM",
        "2:30 PM",
        "3:00 PM"
    ];

    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(Doctors);
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        // Stub: return all slots regardless of doctor/date
        return Task.FromResult(new List<string>(TimeSlots));
    }

    /// <summary>
    /// Validates patient info and appointment selection against server-side business rules.
    /// Returns a dictionary of field name → error messages. Empty means valid.
    /// </summary>
    public Task<Dictionary<string, List<string>>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, List<string>>();

        // Reject patients with outstanding balance
        if (string.Equals(email, "taken@example.com", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(BookAppointmentModel.Email)] =
                ["Account has outstanding balance"];
        }

        // Reject self-pay patients for doctors who don't accept them
        if (string.Equals(insuranceProvider, "None", StringComparison.Ordinal)
            && string.Equals(doctor, "Dr. Smith", StringComparison.Ordinal))
        {
            errors[nameof(BookAppointmentModel.Doctor)] =
                ["Selected doctor does not accept self-pay patients"];
        }

        // Simulate race condition on a specific slot
        if (string.Equals(timeSlot, "10:00 AM", StringComparison.Ordinal))
        {
            errors[nameof(BookAppointmentModel.TimeSlot)] =
                ["This slot is no longer available"];
        }

        return Task.FromResult(errors);
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_e71bdc2613884f5585f6babd2d1f7454.Services;

public class BookAppointmentModel
{
    // Step 1
    [Required(ErrorMessage = "Patient name is required.")]
    public string? PatientName { get; set; }

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Enter a valid email address.")]
    public string? Email { get; set; }

    [Required(ErrorMessage = "Phone number is required.")]
    public string? Phone { get; set; }

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string? InsuranceProvider { get; set; }

    // Step 2
    [Required(ErrorMessage = "Please select a doctor.")]
    public string? Doctor { get; set; }

    [Required(ErrorMessage = "Appointment date is required.")]
    public DateOnly? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Please select a time slot.")]
    public string? TimeSlot { get; set; }

    [Required(ErrorMessage = "Reason for visit is required.")]
    [MaxLength(500, ErrorMessage = "Reason cannot exceed 500 characters.")]
    public string? Reason { get; set; }
}

/// <summary>
/// Custom attribute that ensures a DateOnly value is in the future.
/// Applied at validation time via manual check so the model stays framework-agnostic.
/// </summary>
public class FutureDateAttribute : ValidationAttribute
{
    protected override ValidationResult? IsValid(object? value, ValidationContext context)
    {
        if (value is DateOnly date && date <= DateOnly.FromDateTime(DateTime.Today))
        {
            return new ValidationResult(
                "Appointment date must be in the future.",
                [context.MemberName!]);
        }
        return ValidationResult.Success;
    }
}

