@page "/book-appointment"
@rendermode InteractiveServer
@using sv_e71bdc2613884f5585f6babd2d1f7454.Services
@inject AppointmentService AppointmentService

<PageTitle>Book Appointment</PageTitle>

<h2>Book an Appointment</h2>

<EditForm EditContext="editContext" OnValidSubmit="HandleSubmit" FormName="book-appointment">
    <DataAnnotationsValidator />
    <CustomValidator @ref="customValidator" />

    @* ───── STEP 1 ───── *@
    <fieldset>
        <legend>Patient Information</legend>

        <div class="mb-3">
            <label class="form-label">Patient Name</label>
            <InputText class="form-control" @bind-Value="model.PatientName" />
            <ValidationMessage For="() => model.PatientName" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email</label>
            <InputText class="form-control" @bind-Value="model.Email" />
            <ValidationMessage For="() => model.Email" />
        </div>

        <div class="mb-3">
            <label class="form-label">Phone</label>
            <InputText class="form-control" @bind-Value="model.Phone" />
            <ValidationMessage For="() => model.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label">Insurance Provider</label>
            <InputSelect class="form-select" @bind-Value="model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => model.InsuranceProvider" />
        </div>
    </fieldset>

    @if (!showStep2)
    {
        <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
            Next
        </button>
    }

    @* ───── STEP 2 ───── *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Appointment Details</legend>

            <div class="mb-3">
                <label class="form-label">Preferred Doctor</label>
                <InputSelect class="form-select" @bind-Value="model.Doctor"
                             @bind-Value:after="OnDoctorOrDateChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.Doctor" />
            </div>

            <div class="mb-3">
                <label class="form-label">Appointment Date</label>
                <InputDate class="form-control" @bind-Value="model.AppointmentDate"
                           @bind-Value:after="OnDoctorOrDateChanged" />
                <ValidationMessage For="() => model.AppointmentDate" />
            </div>

            <div class="mb-3">
                <label class="form-label">Time Slot</label>
                <InputSelect class="form-select" @bind-Value="model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in availableSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.TimeSlot" />
            </div>

            <div class="mb-3">
                <label class="form-label">Reason for Visit</label>
                <InputTextArea class="form-control" rows="3" @bind-Value="model.Reason" />
                <ValidationMessage For="() => model.Reason" />
            </div>

            <button type="button" class="btn btn-outline-secondary me-2" @onclick="BackToStep1">
                Back
            </button>
            <button type="button" class="btn btn-info me-2" disabled="@isSubmitting"
                    @onclick="CheckAvailability">
                @(isSubmitting ? "Checking..." : "Check Availability")
            </button>
            <button type="submit" class="btn btn-success" disabled="@(!availabilityChecked || isSubmitting)">
                Confirm Appointment
            </button>
        </fieldset>
    }

    @if (submitted)
    {
        <div class="alert alert-success mt-4">
            Appointment booked successfully!
        </div>
    }
</EditForm>

@code {
    private BookAppointmentModel model = new();
    private EditContext editContext = default!;
    private CustomValidator? customValidator;

    private bool showStep2;
    private bool isSubmitting;
    private bool availabilityChecked;
    private bool submitted;

    private List<string> doctors = [];
    private List<string> availableSlots = [];

    // Step 1 field names used for partial validation
    private static readonly string[] Step1Fields =
        [nameof(BookAppointmentModel.PatientName),
         nameof(BookAppointmentModel.Email),
         nameof(BookAppointmentModel.Phone),
         nameof(BookAppointmentModel.InsuranceProvider)];

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(model);
        doctors = await AppointmentService.GetDoctorsAsync();
    }

    /// <summary>
    /// Validates only Step 1 fields before revealing Step 2.
    /// </summary>
    private void ProceedToStep2()
    {
        // Run full validation then check if any Step 1 fields have errors
        editContext.Validate();

        var hasStep1Errors = editContext
            .GetValidationMessages()
            .Any() && Step1Fields.Any(f =>
                editContext.GetValidationMessages(editContext.Field(f)).Any());

        // Also make sure every step-1 field has a value
        bool step1Complete =
            !string.IsNullOrWhiteSpace(model.PatientName) &&
            !string.IsNullOrWhiteSpace(model.Email) &&
            !string.IsNullOrWhiteSpace(model.Phone) &&
            !string.IsNullOrWhiteSpace(model.InsuranceProvider);

        if (step1Complete && !Step1Fields.Any(f =>
                editContext.GetValidationMessages(editContext.Field(f)).Any()))
        {
            showStep2 = true;
        }
    }

    private void BackToStep1()
    {
        showStep2 = false;
        availabilityChecked = false;
    }

    private async Task OnDoctorOrDateChanged()
    {
        availabilityChecked = false;

        if (!string.IsNullOrEmpty(model.Doctor) && model.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentService.GetAvailableTimeSlotsAsync(
                model.Doctor, model.AppointmentDate.Value);
        }
        else
        {
            availableSlots = [];
        }

        // Clear previously selected slot when options change
        model.TimeSlot = null;
    }

    /// <summary>
    /// Runs full client + server validation. Server errors appear next to specific fields.
    /// </summary>
    private async Task CheckAvailability()
    {
        customValidator?.ClearErrors();
        availabilityChecked = false;

        bool clientValid = editContext.Validate();
        if (!clientValid) return;

        isSubmitting = true;
        try
        {
            var errors = await AppointmentService.ValidatePatientAsync(
                model.Email!,
                model.InsuranceProvider!,
                model.Doctor!,
                model.TimeSlot!);

            if (errors.Count > 0)
            {
                customValidator!.DisplayErrors(errors);
                return;
            }

            availabilityChecked = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private async Task HandleSubmit()
    {
        if (!availabilityChecked)
        {
            await CheckAvailability();
            if (!availabilityChecked) return;
        }

        submitted = true;
    }
}

